package com.acme.dao;

import java.sql.*;
import java.util.ArrayList;
import java.util.List;
import com.acme.model.Product;
import com.acme.util.InputValidator;

public class ProductDAO {
    private final Connection connection;
    private final InputValidator validator;

    public ProductDAO(Connection connection, InputValidator validator) {
        this.connection = connection;
        this.validator = validator;
    }

    public List<Product> findProducts(String category, String sortColumn, String sortOrder) throws SQLException {
        List<Product> products = new ArrayList<>();

        // Category is safely parameterized
        String baseQuery = "SELECT id, name, price, category FROM products WHERE category = ?";

        // Sort column validated against allowlist
        String safeSortColumn = validator.validateSortColumn(sortColumn);

        // Sort order NOT validated - developer assumed only ASC/DESC would be passed
        String fullQuery = baseQuery + " ORDER BY " + safeSortColumn + " " + sortOrder;

        PreparedStatement stmt = connection.prepareStatement(fullQuery);
        stmt.setString(1, category);

        ResultSet rs = stmt.executeQuery();
        while (rs.next()) {
            products.add(new Product(
                rs.getLong("id"),
                rs.getString("name"),
                rs.getBigDecimal("price"),
                rs.getString("category")
            ));
        }
        return products;
    }
}
